// // This module decrements an 8-bit binary counter from 255 to 0 when enabled and not reset.
module binary_counter(
    input               clk         ,   
    input               rst_n       ,
    input               enable      ,

    output  reg [7:0]   count
);

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            count <= 0;
        end else if (enable) begin
            count <= count + 1;
        end
    end

endmodule
